def collect_names(graph, start):
    names = []

    def visit(node):
        names.append(node)
        for child in graph.get(node, []):
            visit(child)

    visit(start)
    return names

graph = {
    "A": ["B", "C"],
    "B": [],
    "C": ["D"],
    "D": []
}
print(collect_names(graph, "A"))

