node Employee {
    has name: str;
    has salary: int;
}

walker PayrollTotal {
    has total: int = 0;

    can begin with `root entry {
        visit [-->];
    }

    can add_salary with Employee entry {
        self.total += here.salary;
        visit [-->];
    }
}

with entry {
    manager = Employee(name="Mira", salary=120);
    engineer = Employee(name="Lee", salary=90);
    designer = Employee(name="Ari", salary=80);
    intern = Employee(name="Noor", salary=30);
    root ++> manager;
    manager ++> engineer;
    manager ++> designer;
    engineer ++> intern;
    payroll = PayrollTotal();
    root spawn payroll;
    print(payroll.total);
}
